import { Router } from 'express';
import { homepageDB } from '../db/inMemory.js';

const router = Router();

router.get('/', (_req, res) => {
  res.json({ success: true, data: homepageDB });
});

router.put('/', (req, res) => {
  Object.assign(homepageDB, req.body);
  res.json({ success: true, data: homepageDB });
});

export default router;
