import { Router } from 'express';
import { ashramsDB } from '../db/inMemory.js';
import type { Ashram } from '../types.js';

const router = Router();

router.get('/', (_req, res) => {
  res.json({ success: true, count: ashramsDB.length, data: ashramsDB });
});

router.post('/', (req, res) => {
  const newAshram: Ashram = { id: `ash-${Date.now()}`, ...req.body };
  ashramsDB.unshift(newAshram);
  res.status(201).json({ success: true, data: newAshram });
});

router.put('/:id', (req, res) => {
  const index = ashramsDB.findIndex(a => a.id === req.params.id);
  if (index !== -1) {
    ashramsDB[index] = { ...ashramsDB[index], ...req.body };
    res.json({ success: true, data: ashramsDB[index] });
  } else {
    res.status(404).json({ success: false, message: 'Ashram not found' });
  }
});

router.delete('/:id', (req, res) => {
  ashramsDB.splice(0, ashramsDB.length, ...ashramsDB.filter(a => a.id !== req.params.id));
  res.json({ success: true, message: 'Ashram deleted successfully' });
});

export default router;
