import { Router } from 'express';
import { aboutDB } from '../db/inMemory.js';

const router = Router();

router.get('/', (_req, res) => {
  res.json({ success: true, data: aboutDB });
});

router.put('/', (req, res) => {
  Object.assign(aboutDB, req.body);
  res.json({ success: true, data: aboutDB });
});

export default router;
