import { GoogleGenAI } from '@google/genai';

let aiClient: GoogleGenAI | null = null;

export function getGeminiClient(): GoogleGenAI {
  if (!aiClient) {
    const key = process.env.GEMINI_API_KEY;
    if (!key) {
      console.warn('WARNING: GEMINI_API_KEY not set. Gemini runs in mock mode.');
    }
    aiClient = new GoogleGenAI({
      apiKey: key || 'MOCK_KEY',
      httpOptions: { headers: { 'User-Agent': 'aistudio-build' } }
    });
  }
  return aiClient;
}

export function generateMockGuruResponse(msg: string): string {
  const lowerMsg = msg.toLowerCase();

  if (lowerMsg.includes('peace') || lowerMsg.includes('anxiety') || lowerMsg.includes('stress')) {
    return `### Hare Krishna, dear seeker. ✨
Real peace enters when we quiet the ego and align our lives with the Supreme Will. Bhagavad Gita (2.70) tells us:
> *āpūryamāṇam acala-pratiṣṭhaṁ samudram āpaḥ praviśanti yadvat*
"A person who is not disturbed by the incessant flow of desires can alone achieve peace."

**Spiritual Wisdom:**
1. **Chant the Maha-Mantra:** *Hare Krishna, Hare Krishna, Krishna Krishna, Hare Hare / Hare Rama, Hare Rama, Rama Rama, Hare Hare*
2. **Simple Service (Seva):** One selfless act daily without expectation.
3. **Pure Prasadam:** Vegetarian foods offered in devotion.`;
  }

  if (lowerMsg.includes('karma') || lowerMsg.includes('destiny') || lowerMsg.includes('future')) {
    return `### Joyful greetings, sincere soul. 🌸
Karma is not punishment, but a loving mirror reflecting our choices. In Bhagavad-gita (18.66):
> *sarva-dharmān parityajya mām ekaṁ śaraṇaṁ vraja*
"Abandon all varieties of religion and just surrender unto Me. I shall deliver you from all sinful reactions."

When you offer your work as devotional love, you become free from karma's binding threads.`;
  }

  if (lowerMsg.includes('guru') || lowerMsg.includes('lineage') || lowerMsg.includes('prabhupada')) {
    return `### Pranams. 🙏
A true guru is a clear medium through which divine love passes. Sri Chaitanya Mahaprabhu taught:
> *yāre dekha, tāre kaha 'kṛṣṇa'-upadeśa*
"Instruct everyone to follow the teachings of Sri Krishna."

Our lineage comes in an unbroken chain (*Parampara*) from Sri Krishna Himself.`;
  }

  return `### Hare Krishna! 🙏
The scriptures teach that the ultimate spiritual path consists of:
- **Śravaṇam:** Hearing the sacred scriptures.
- **Kīrtanam:** Singing and chanting the holy names.
- **Smaraṇam:** Remembering the divine presence in all living entities.

Please ask about **mantra meditation, karma, guru lineage, or Gita chapters**. May your heart be filled with serenity! ✨`;
}
