import { Router } from 'express';
import { gurusDB } from '../db/inMemory.js';
import type { Guru } from '../types.js';

const router = Router();

router.get('/', (_req, res) => {
  res.json({ success: true, count: gurusDB.length, data: gurusDB });
});

router.post('/', (req, res) => {
  const newGuru: Guru = { id: `g-${Date.now()}`, ...req.body };
  gurusDB.unshift(newGuru);
  res.status(201).json({ success: true, data: newGuru });
});

router.put('/:id', (req, res) => {
  const index = gurusDB.findIndex(g => g.id === req.params.id);
  if (index !== -1) {
    gurusDB[index] = { ...gurusDB[index], ...req.body };
    res.json({ success: true, data: gurusDB[index] });
  } else {
    res.status(404).json({ success: false, message: 'Guru not found' });
  }
});

router.delete('/:id', (req, res) => {
  const before = gurusDB.length;
  gurusDB.splice(0, gurusDB.length, ...gurusDB.filter(g => g.id !== req.params.id));
  res.json({ success: true, message: 'Guru deleted successfully', deleted: gurusDB.length < before });
});

export default router;
