import { Router } from 'express';
import { eventsDB } from '../db/inMemory.js';
import type { AshramEvent } from '../types.js';

const router = Router();

router.get('/', (_req, res) => {
  res.json({ success: true, count: eventsDB.length, data: eventsDB });
});

router.post('/', (req, res) => {
  const newEvent: AshramEvent = { id: `ev-${Date.now()}`, registrationsCount: 0, ...req.body };
  eventsDB.unshift(newEvent);
  res.status(201).json({ success: true, data: newEvent });
});

router.put('/:id', (req, res) => {
  const index = eventsDB.findIndex(e => e.id === req.params.id);
  if (index !== -1) {
    eventsDB[index] = { ...eventsDB[index], ...req.body };
    res.json({ success: true, data: eventsDB[index] });
  } else {
    res.status(404).json({ success: false, message: 'Event not found' });
  }
});

router.post('/:id/register', (req, res) => {
  const index = eventsDB.findIndex(e => e.id === req.params.id);
  if (index !== -1) {
    const event = eventsDB[index];
    if (event.availableTickets > 0) {
      event.availableTickets -= 1;
      event.registrationsCount += 1;
      res.json({ success: true, data: event });
    } else {
      res.status(400).json({ success: false, message: 'Event is fully booked' });
    }
  } else {
    res.status(404).json({ success: false, message: 'Event not found' });
  }
});

router.delete('/:id', (req, res) => {
  eventsDB.splice(0, eventsDB.length, ...eventsDB.filter(e => e.id !== req.params.id));
  res.json({ success: true, message: 'Event deleted successfully' });
});

export default router;
