import { Router } from 'express';
import { getGeminiClient, generateMockGuruResponse } from '../services/gemini.js';

const router = Router();

const SYSTEM_INSTRUCTION = `You are a wise, serene, compassionate spiritual guide from the ancient Gaudiya Vaishnava tradition, based on the teachings of Lord Chaitanya and Srila Prabhupada. Answer questions about life, spirituality, yoga, mantras, meditation, karma, and ancient scriptures (Bhagavad-gita, Srimad Bhagavatam). Keep your tone gentle, humble, deeply reassuring, and spiritual. When appropriate, write relevant Sanskrit verses with beautiful translations. Use rich Markdown formatting. Do NOT mention AI, instruction limits, or system models. Speak as a real loving guide. Keep answers concise, peaceful, and under 200 words.`;

router.post('/', async (req, res) => {
  const { message } = req.body;
  if (!message) {
    return res.status(400).json({ success: false, message: 'Message is required' });
  }

  try {
    const apiKey = process.env.GEMINI_API_KEY;
    if (!apiKey || apiKey === 'MY_GEMINI_API_KEY' || apiKey === 'MOCK_KEY') {
      const mockResult = generateMockGuruResponse(message);
      return res.json({ success: true, text: mockResult, mode: 'spiritual-simulation' });
    }

    const client = getGeminiClient();
    const response = await client.models.generateContent({
      model: 'gemini-3.5-flash',
      contents: message,
      config: { systemInstruction: SYSTEM_INSTRUCTION, temperature: 0.8, topP: 0.95 }
    });

    if (response && response.text) {
      res.json({ success: true, text: response.text, mode: 'gemini' });
    } else {
      throw new Error('Empty response from Gemini');
    }
  } catch (error: any) {
    console.error('Gemini API failed, using fallback:', error.message);
    res.json({ success: true, text: generateMockGuruResponse(message), mode: 'spiritual-fallback' });
  }
});

export default router;
