import { Router } from 'express';
import { ordersDB, productsDB } from '../db/inMemory.js';
import type { Order } from '../types.js';

const router = Router();

router.post('/', (req, res) => {
  const { userId, items, subtotal, couponCode, discount, total, shippingAddress } = req.body;
  if (!userId || !items || !items.length || !shippingAddress) {
    return res.status(400).json({ success: false, message: 'Incomplete order information' });
  }

  const newOrder: Order = {
    id: `ord-${Math.floor(1000 + Math.random() * 9000)}`,
    userId,
    items,
    subtotal,
    couponCode,
    discount,
    total,
    shippingAddress,
    paymentStatus: 'Paid',
    orderStatus: 'Processing',
    trackingNumber: `TRK-VRN-${Math.floor(100000 + Math.random() * 900000)}`,
    orderDate: new Date().toISOString()
  };

  ordersDB.unshift(newOrder);

  items.forEach((item: any) => {
    const productIndex = productsDB.findIndex(p => p.id === item.productId);
    if (productIndex !== -1) {
      const remaining = Math.max(0, productsDB[productIndex].stock - item.quantity);
      productsDB[productIndex].stock = remaining;
      if (remaining === 0) productsDB[productIndex].isAvailable = false;
    }
  });

  res.status(201).json({ success: true, data: newOrder });
});

router.get('/', (req, res) => {
  const { userId } = req.query;
  const data = userId ? ordersDB.filter(o => o.userId === userId) : ordersDB;
  res.json({ success: true, data });
});

router.put('/:id/status', (req, res) => {
  const index = ordersDB.findIndex(o => o.id === req.params.id);
  if (index !== -1) {
    ordersDB[index].orderStatus = req.body.orderStatus;
    res.json({ success: true, data: ordersDB[index] });
  } else {
    res.status(404).json({ success: false, message: 'Order not found' });
  }
});

export default router;
