import { Router } from 'express';
import { usersDB } from '../db/inMemory.js';
import type { UserProfile } from '../types.js';

const router = Router();

router.post('/register', (req, res) => {
  const { name, email, phone } = req.body;
  if (!name || !email) {
    return res.status(400).json({ success: false, message: 'Name and Email are required' });
  }
  const existing = usersDB.find(u => u.email.toLowerCase() === email.toLowerCase());
  if (existing) {
    return res.json({ success: true, data: existing, message: 'Logged in as existing user' });
  }
  const newUser: UserProfile = {
    id: `usr-${Date.now()}`,
    name,
    email,
    phone,
    role: 'Devotee',
    savedEventIds: [],
    wishlistProductIds: []
  };
  usersDB.push(newUser);
  res.status(201).json({ success: true, data: newUser, message: 'Registration successful' });
});

router.post('/login', (req, res) => {
  const { email } = req.body;
  if (!email) {
    return res.status(400).json({ success: false, message: 'Email is required' });
  }
  const user = usersDB.find(u => u.email.toLowerCase() === email.toLowerCase());
  if (user) {
    return res.json({ success: true, data: user });
  }
  const newUser: UserProfile = {
    id: `usr-${Date.now()}`,
    name: email.split('@')[0].toUpperCase(),
    email,
    role: email === 'admin@ashram.org' ? 'Super Admin' : 'Devotee',
    savedEventIds: [],
    wishlistProductIds: []
  };
  usersDB.push(newUser);
  res.json({ success: true, data: newUser, message: 'New user initialized' });
});

router.put('/profile/:id', (req, res) => {
  const index = usersDB.findIndex(u => u.id === req.params.id);
  if (index !== -1) {
    usersDB[index] = { ...usersDB[index], ...req.body };
    res.json({ success: true, data: usersDB[index] });
  } else {
    res.status(404).json({ success: false, message: 'User profile not found' });
  }
});

export default router;
