import { Router } from 'express';
import { productsDB } from '../db/inMemory.js';
import type { Product } from '../types.js';

const router = Router();

router.get('/', (_req, res) => {
  res.json({ success: true, count: productsDB.length, data: productsDB });
});

router.post('/', (req, res) => {
  const newProduct: Product = { id: `p-${Date.now()}`, reviews: [], rating: 5, ...req.body };
  productsDB.unshift(newProduct);
  res.status(201).json({ success: true, data: newProduct });
});

router.put('/:id', (req, res) => {
  const index = productsDB.findIndex(p => p.id === req.params.id);
  if (index !== -1) {
    productsDB[index] = { ...productsDB[index], ...req.body };
    res.json({ success: true, data: productsDB[index] });
  } else {
    res.status(404).json({ success: false, message: 'Product not found' });
  }
});

router.delete('/:id', (req, res) => {
  productsDB.splice(0, productsDB.length, ...productsDB.filter(p => p.id !== req.params.id));
  res.json({ success: true, message: 'Product deleted successfully' });
});

router.post('/:id/reviews', (req, res) => {
  const index = productsDB.findIndex(p => p.id === req.params.id);
  if (index !== -1) {
    const { userName, rating, comment } = req.body;
    const newReview = {
      id: `rev-${Date.now()}`,
      userName: userName || 'Devotee',
      rating: rating || 5,
      comment: comment || 'Radhe Radhe! Very beautiful item.',
      date: new Date().toISOString().split('T')[0]
    };
    productsDB[index].reviews.push(newReview);
    const total = productsDB[index].reviews.reduce((sum, r) => sum + r.rating, 0);
    productsDB[index].rating = parseFloat((total / productsDB[index].reviews.length).toFixed(1));
    res.status(201).json({ success: true, data: productsDB[index] });
  } else {
    res.status(404).json({ success: false, message: 'Product not found' });
  }
});

export default router;
