import { Router } from 'express';
import { usersDB } from '../db/inMemory.js';

const router = Router();

router.post('/:userId/wishlist', (req, res) => {
  const { productId } = req.body;
  const index = usersDB.findIndex(u => u.id === req.params.userId);
  if (index !== -1) {
    const user = usersDB[index];
    const itemIndex = user.wishlistProductIds.indexOf(productId);
    if (itemIndex === -1) {
      user.wishlistProductIds.push(productId);
    } else {
      user.wishlistProductIds.splice(itemIndex, 1);
    }
    res.json({ success: true, wishlist: user.wishlistProductIds });
  } else {
    res.status(404).json({ success: false, message: 'User not found' });
  }
});

router.post('/:userId/events', (req, res) => {
  const { eventId } = req.body;
  const index = usersDB.findIndex(u => u.id === req.params.userId);
  if (index !== -1) {
    const user = usersDB[index];
    const itemIndex = user.savedEventIds.indexOf(eventId);
    if (itemIndex === -1) {
      user.savedEventIds.push(eventId);
    } else {
      user.savedEventIds.splice(itemIndex, 1);
    }
    res.json({ success: true, savedEvents: user.savedEventIds });
  } else {
    res.status(404).json({ success: false, message: 'User not found' });
  }
});

export default router;
