import { Router } from 'express';
import { blogsDB } from '../db/inMemory.js';

const router = Router();

router.get('/', (_req, res) => {
  res.json({ success: true, data: blogsDB });
});

router.post('/', (req, res) => {
  const newBlog = {
    id: `blog-${Date.now()}`,
    publishDate: new Date().toISOString().split('T')[0],
    title: req.body.title,
    summary: req.body.summary,
    content: req.body.content,
    author: req.body.author || 'Ashram Scribe',
    coverUrl: req.body.coverUrl || 'https://images.unsplash.com/photo-1544161515-4ab6ce6db874?auto=format&fit=crop&q=80&w=600',
    tags: req.body.tags || ['Wisdom'],
    readingTime: req.body.readingTime || '5 mins read'
  };
  blogsDB.unshift(newBlog as any);
  res.status(201).json({ success: true, data: newBlog });
});

router.put('/:id', (req, res) => {
  const index = blogsDB.findIndex(b => b.id === req.params.id);
  if (index !== -1) {
    blogsDB[index] = { ...blogsDB[index], ...req.body };
    res.json({ success: true, data: blogsDB[index] });
  } else {
    res.status(404).json({ success: false, message: 'Blog Article not found' });
  }
});

router.delete('/:id', (req, res) => {
  blogsDB.splice(0, blogsDB.length, ...blogsDB.filter(b => b.id !== req.params.id));
  res.json({ success: true, message: 'Blog Article deleted successfully' });
});

export default router;
